                const key = `${slope}`;
                if (!slopes.has(key)) {
                    slopes.set(key, 0);
                }
                slopes.set(key, slopes.get(key) + 1);
            }
        }
    }

    // Calculate the number of trapezoids
    let count = 0;
    for (const [slope, cnt] of slopes.entries()) {
        if (cnt >= 2) {
            // Number of ways to choose 2 pairs of points with the same slope
            const ways = cnt * (cnt - 1) / 2;
            count += ways;
        }
    }

